package com.gtky.app.data.database

import com.gtky.app.data.entity.AppConfig
import com.gtky.app.data.entity.QuestionType
import com.gtky.app.data.entity.SurveyQuestion
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

object DataSeeder {

    suspend fun seedIfNeeded(db: GTKYDatabase) = withContext(Dispatchers.IO) {
        if (db.surveyQuestionDao().getQuestionCount() == 0) {
            db.surveyQuestionDao().insertQuestions(buildQuestions())
        }
        if (db.appConfigDao().getValue("admin_pin") == null) {
            db.appConfigDao().setValue(AppConfig("admin_pin", "1234"))
        }
        if (db.appConfigDao().getValue("seeded") == null) {
            db.appConfigDao().setValue(AppConfig("seeded", "true"))
        }
        if (db.appConfigDao().getValue("seeded_es") == null) {
            val patch = buildSpanishPatch()
            db.surveyQuestionDao().getAllQuestionsOnce().forEach { q ->
                val sp = patch[q.questionTemplate]
                if (sp != null) {
                    db.surveyQuestionDao().updateSpanish(q.id, sp.first, sp.second)
                }
            }
            db.appConfigDao().setValue(AppConfig("seeded_es", "true"))
        }
    }

    private fun tf(
        template: String, opt1: String, opt2: String, category: String,
        templateEs: String, opt1Es: String, opt2Es: String
    ) = SurveyQuestion(
        questionTemplate = template,
        questionTemplateEs = templateEs,
        type = QuestionType.TRUE_FALSE,
        optionsJson = """["$opt1","$opt2"]""",
        optionsJsonEs = """["$opt1Es","$opt2Es"]""",
        category = category
    )

    private fun mc(
        template: String, opts: List<String>, category: String,
        templateEs: String, optsEs: List<String>
    ) = SurveyQuestion(
        questionTemplate = template,
        questionTemplateEs = templateEs,
        type = QuestionType.MULTIPLE_CHOICE,
        optionsJson = opts.joinToString(",", "[", "]") { "\"$it\"" },
        optionsJsonEs = optsEs.joinToString(",", "[", "]") { "\"$it\"" },
        category = category
    )

    private fun buildSpanishPatch(): Map<String, Pair<String, String>> {
        return buildQuestions().associate { q ->
            q.questionTemplate to Pair(q.questionTemplateEs, q.optionsJsonEs)
        }
    }

